#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long M, H;
        scanf("%lld %lld", &M, &H);
        long long bmi = M / (H * H);
        int cat;
        if (bmi <= 18) cat = 1;
        else if (bmi <= 24) cat = 2;
        else if (bmi <= 29) cat = 3;
        else cat = 4;
        printf("%d\n", cat);
    }
    return 0;
}

